import{_ as t,a,b as o,c as n,d as r,e as l,f as d}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as i,o as s,c as p,a2 as c}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"Přidání kanálu Discord","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/discord.md","filePath":"cs-CZ/upload/discord.md","lastUpdated":1781962217000}'),v={name:"cs-CZ/upload/discord.md"};function h(u,e,k,b,m,y){return s(),p("div",null,[...e[0]||(e[0]=[c('<h1 id="pridani-kanalu-discord" tabindex="-1">Přidání kanálu Discord <a class="header-anchor" href="#pridani-kanalu-discord" aria-label="Permalink to &quot;Přidání kanálu Discord&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Účel</th></tr></thead><tbody><tr><td>Účet Discord</td><td>Pro vytvoření serveru, kanálu a vývojářské aplikace.</td></tr><tr><td>Discord server</td><td>Bot musí být na serveru, než může přistupovat ke kanálu.</td></tr><tr><td>Textový kanál</td><td>Obrázky a soubory se budou posílat do tohoto kanálu.</td></tr><tr><td>Discord Developer Portal</td><td>Pro vytvoření aplikace, bota a získání <code>Bot Token</code>.</td></tr></tbody></table><h2 id="kde-ho-pridat" tabindex="-1">Kde ho přidat <a class="header-anchor" href="#kde-ho-pridat" aria-label="Permalink to &quot;Kde ho přidat&quot;">​</a></h2><ol><li>Otevřete Nastavení systému.</li><li>Přejděte do Nastavení nahrávání.</li><li>Klikněte vpravo nahoře na Přidat kanál.</li><li>Vyberte <code>Discord</code>.</li></ol><h2 id="prehled-poli" tabindex="-1">Přehled polí <a class="header-anchor" href="#prehled-poli" aria-label="Permalink to &quot;Přehled polí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Co dělá</th><th>Povinné</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>Discord Primary</code>.</td><td>Ano</td></tr><tr><td>Bot Token</td><td>Token Discord bota.</td><td>Ano</td></tr><tr><td>Channel ID</td><td>ID cílového textového kanálu.</td><td>Ano</td></tr><tr><td>Proxy URL (volitelné)</td><td>Použijte jen při nestabilním přístupu k Discord CDN. Zadejte celý URL včetně <code>https://</code>.</td><td>Ne</td></tr></tbody></table><h2 id="postup-nastaveni" tabindex="-1">Postup nastavení <a class="header-anchor" href="#postup-nastaveni" aria-label="Permalink to &quot;Postup nastavení&quot;">​</a></h2><h3 id="_1-vytvorte-discord-server-a-textovy-kanal" tabindex="-1">1. Vytvořte Discord server a textový kanál <a class="header-anchor" href="#_1-vytvorte-discord-server-a-textovy-kanal" aria-label="Permalink to &quot;1. Vytvořte Discord server a textový kanál&quot;">​</a></h3><ol><li>Otevřete Discord.</li><li>Vytvořte nový server nebo použijte existující server, který vlastníte.</li><li>Na serveru vytvořte textový kanál.</li></ol><p><img src="'+t+'" alt="Vytvoření serveru" loading="lazy"></p><h3 id="_2-vytvorte-bota-v-discord-developer-portal" tabindex="-1">2. Vytvořte bota v Discord Developer Portal <a class="header-anchor" href="#_2-vytvorte-bota-v-discord-developer-portal" aria-label="Permalink to &quot;2. Vytvořte bota v Discord Developer Portal&quot;">​</a></h3><ol><li>Otevřete Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Klikněte na <code>New Application</code>.</li><li>Zadejte název aplikace a vytvořte ji.</li><li>V levém panelu otevřete stránku <code>Bot</code>.</li><li>Na stránce <code>Bot</code> vygenerujte nebo resetujte token.</li><li>Token uložte.</li></ol><p>Tento token zadáte v ImgBed jako <code>Bot Token</code>.</p><p><img src="'+a+'" alt="Zobrazení tokenu bota" loading="lazy"></p><h3 id="_3-vygenerujte-oauth2-pozvanku-a-nainstalujte-bota" tabindex="-1">3. Vygenerujte OAuth2 pozvánku a nainstalujte bota <a class="header-anchor" href="#_3-vygenerujte-oauth2-pozvanku-a-nainstalujte-bota" aria-label="Permalink to &quot;3. Vygenerujte OAuth2 pozvánku a nainstalujte bota&quot;">​</a></h3><ol><li>V levém panelu otevřete stránku <code>OAuth2</code>.</li><li>V scopes vyberte <code>bot</code>.</li><li>V části oprávnění zapněte:</li></ol><table tabindex="0"><thead><tr><th>Oprávnění</th><th>Povinné</th></tr></thead><tbody><tr><td>View Channels</td><td>Ano</td></tr><tr><td>Send Messages</td><td>Ano</td></tr><tr><td>Attach Files</td><td>Ano</td></tr><tr><td>Read Message History</td><td>Ano</td></tr></tbody></table><ol start="4"><li>Dole na stránce potvrďte, že typ integrace je <code>Guild Install</code>.</li><li>Zkopírujte vygenerovaný URL.</li><li>Otevřete ho v prohlížeči.</li><li>Vyberte cílový server.</li><li>Dokončete autorizaci.</li></ol><p><img src="'+o+'" alt="Výběr oprávnění bota v OAuth2" loading="lazy"></p><p><img src="'+n+'" alt="Pozvání bota do kanálu" loading="lazy"></p><h3 id="_4-zapnete-vyvojarsky-rezim-a-zkopirujte-channel-id" tabindex="-1">4. Zapněte vývojářský režim a zkopírujte Channel ID <a class="header-anchor" href="#_4-zapnete-vyvojarsky-rezim-a-zkopirujte-channel-id" aria-label="Permalink to &quot;4. Zapněte vývojářský režim a zkopírujte Channel ID&quot;">​</a></h3><ol><li>Klikněte na ozubené kolo vedle avatara vlevo dole.</li><li>V levém panelu otevřete Advanced.</li><li>Zapněte Developer Mode.</li><li>Vraťte se do cílového textového kanálu.</li><li>Klikněte pravým tlačítkem na název kanálu.</li><li>Klikněte na Copy Channel ID.</li></ol><p>Zkopírované číslo je <code>Channel ID</code> požadované ImgBed.</p><p><img src="'+r+'" alt="Zapnutí vývojářského režimu" loading="lazy"></p><p><img src="'+l+'" alt="Kopírování Channel ID" loading="lazy"></p><h3 id="_5-vyplnte-discord-kanal-v-imgbed" tabindex="-1">5. Vyplňte Discord kanál v ImgBed <a class="header-anchor" href="#_5-vyplnte-discord-kanal-v-imgbed" aria-label="Permalink to &quot;5. Vyplňte Discord kanál v ImgBed&quot;">​</a></h3><p>Vraťte se do konfiguračního dialogu a vyplňte:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Hodnota</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Vlastní název, například <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token ze stránky <code>Bot</code> v Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID zkopírované z Discordu.</td></tr><tr><td>Proxy URL (volitelné)</td><td>Jen pokud je potřeba, například <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Po dokončení klikněte na Uložit.</p><p><img src="'+d+`" alt="Přidání konfigurace Discord" loading="lazy"></p><h2 id="overeni" tabindex="-1">Ověření <a class="header-anchor" href="#overeni" aria-label="Permalink to &quot;Ověření&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak ověřit</th></tr></thead><tbody><tr><td>Karta kanálu se zobrazuje</td><td>Po uložení by se v Nastavení nahrávání měla zobrazit karta Discord.</td></tr><tr><td>Kanál lze zapnout</td><td>Přepínač Aktivní zůstane zapnutý.</td></tr><tr><td>Konfigurace je uložena</td><td>Detail ukazuje uložený Bot Token a Channel ID.</td></tr><tr><td>Upload funguje</td><td>Nahrajte testovací obrázek a ověřte, že se objevil v cílovém textovém kanálu Discord.</td></tr></tbody></table><h2 id="rychly-checklist" tabindex="-1">Rychlý checklist <a class="header-anchor" href="#rychly-checklist" aria-label="Permalink to &quot;Rychlý checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vytvořte Discord server</span></span>
<span class="line"><span>-&gt; Vytvořte textový kanál</span></span>
<span class="line"><span>-&gt; Vytvořte bota v Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Uložte Bot Token ze stránky Bot</span></span>
<span class="line"><span>-&gt; V OAuth2 vyberte bot, View Channels, Send Messages, Attach Files a Read Message History</span></span>
<span class="line"><span>-&gt; Zkopírujte vygenerovaný URL a autorizujte bota na cílovém serveru</span></span>
<span class="line"><span>-&gt; Ověřte, že cílový textový kanál povoluje stejná oprávnění</span></span>
<span class="line"><span>-&gt; Zapněte Developer Mode</span></span>
<span class="line"><span>-&gt; Klikněte pravým tlačítkem na cílový textový kanál a zkopírujte Channel ID</span></span>
<span class="line"><span>-&gt; Zadejte Bot Token a Channel ID do ImgBed</span></span>
<span class="line"><span>-&gt; Uložte a nahrajte testovací obrázek</span></span></code></pre></div><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const j=i(v,[["render",h]]);export{z as __pageData,j as default};
